using BotFramework.Discord.Commands;using BotFramework.Discord.Routing;using Games.Bowling.Application.Services;
namespace Games.Bowling.Discord;
public sealed class BowlingDiscordHandler(IBowlingService service):IDiscordMessageHandler{public bool CanHandle(DiscordMessageContext c)=>DiscordCommand.Is(c,"bowling");public async Task HandleAsync(DiscordMessageContext c){var p=DiscordCommand.Parts(c);if(p.Length!=2||!int.TryParse(p[1],out var amount)||amount<=0){await DiscordCommand.ReplyAsync(c,"Использование: `bowling <ставка>`");return;}var u=DiscordCommand.UserId(c);var s=DiscordCommand.ScopeId(c);var src=DiscordCommand.SourceId(c);var n=DiscordCommand.DisplayName(c);_ = await service.PlaceBetAsync(u,n,s,amount,src,c.CancellationToken);var face=DiscordCommand.RandomFace(1,6);var r=await service.RollAsync(u,n,s,face,src,c.CancellationToken);await DiscordCommand.ReplyResultAsync(c,r,"Bowling: "+face);}}
public static class BowlingDiscordModule{public static IServiceCollection AddBowlingDiscord(this IServiceCollection s)=>s.AddScoped<IDiscordMessageHandler,BowlingDiscordHandler>();}
